package com.example.loginprototype;

import android.content.Context;
import android.content.SharedPreferences;

import androidx.annotation.Nullable;

public final class SessionPrefs {
    private static final String PREFS_NAME = "session_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "auth_token";

    private SessionPrefs() {}

    private static SharedPreferences prefs(Context context) {
        return context.getApplicationContext().getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public static void saveSession(Context context, String email, String authToken) {
        prefs(context).edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, authToken)
                .apply();
    }

    public static boolean hasSession(Context context) {
        String token = getAuthToken(context);
        return token != null && !token.trim().isEmpty();
    }

    @Nullable
    public static String getEmail(Context context) {
        return prefs(context).getString(KEY_EMAIL, null);
    }

    @Nullable
    public static String getAuthToken(Context context) {
        return prefs(context).getString(KEY_TOKEN, null);
    }

    public static void clearSession(Context context) {
        prefs(context).edit().remove(KEY_EMAIL).remove(KEY_TOKEN).apply();
    }
}

package com.example.loginprototype;

public final class AuthResult {
    public final boolean success;
    public final String email;
    public final String token;
    public final String error;

    private AuthResult(boolean success, String email, String token, String error) {
        this.success = success;
        this.email = email;
        this.token = token;
        this.error = error;
    }

    public static AuthResult success(String email, String token) {
        return new AuthResult(true, email, token, null);
    }

    public static AuthResult failure(String error) {
        return new AuthResult(false, null, null, error);
    }
}

package com.example.loginprototype;

import android.os.Handler;
import android.os.Looper;

import java.util.UUID;

public final class AuthRepository {

    public interface Callback {
        void onResult(AuthResult result);
    }

    public void login(String email, String password, Callback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            if (email == null || email.trim().isEmpty()) {
                callback.onResult(AuthResult.failure("Email required"));
                return;
            }
            if (password == null || password.length() < 4) {
                callback.onResult(AuthResult.failure("Password too short"));
                return;
            }
            String token = "demo_" + UUID.randomUUID().toString();
            callback.onResult(AuthResult.success(email.trim(), token));
        }, 600);
    }
}

package com.example.loginprototype;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;
    private TextView errorText;

    private final AuthRepository authRepository = new AuthRepository();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (SessionPrefs.hasSession(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);
        errorText = findViewById(R.id.errorText);

        String rememberedEmail = SessionPrefs.getEmail(this);
        if (!TextUtils.isEmpty(rememberedEmail)) {
            emailInput.setText(rememberedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        errorText.setText("");
        setLoading(true);

        String email = emailInput.getText() != null ? emailInput.getText().toString() : "";
        String password = passwordInput.getText() != null ? passwordInput.getText().toString() : "";

        authRepository.login(email, password, result -> {
            setLoading(false);
            if (result.success) {
                SessionPrefs.saveSession(LoginActivity.this, result.email, result.token);
                startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                finish();
            } else {
                errorText.setText(result.error != null ? result.error : "Login failed");
            }
        });
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }
}

package com.example.loginprototype;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView sessionText;
    private Button logoutButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!SessionPrefs.hasSession(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        sessionText = findViewById(R.id.sessionText);
        logoutButton = findViewById(R.id.logoutButton);

        String email = SessionPrefs.getEmail(this);
        String token = SessionPrefs.getAuthToken(this);

        sessionText.setText("Logged in as: " + (email != null ? email : "") + "\nToken: " + (token != null ? token : ""));

        logoutButton.setOnClickListener(v -> {
            SessionPrefs.clearSession(HomeActivity.this);
            startActivity(new Intent(HomeActivity.this, LoginActivity.class));
            finish();
        });
    }
}

